*Highlighted section: Constructor and Destructor Implementation*

```cpp
UndergraduateStudentProfile::UndergraduateStudentProfile() 
    : fullName(""), studentID(""), gpa(0.0) {}

UndergraduateStudentProfile::UndergraduateStudentProfile(const std::string& name, const std::string& id, double gpa) 
    : fullName(name), studentID(id), gpa(gpa) {}

UndergraduateStudentProfile::~UndergraduateStudentProfile() {}

std::string UndergraduateStudentProfile::getFullName() const {
    return fullName;
}

std::string UndergraduateStudentProfile::getStudentID() const {
    return studentID;
}

double UndergraduateStudentProfile::getGPA() const {
    return gpa;
}
```

*Highlighted section: Accessor and Mutator Methods*

```cpp
void UndergraduateStudentProfile::setFullName(const std::string& name) {
    fullName = name;
}

void UndergraduateStudentProfile::setStudentID(const std::string& id) {
    studentID = id;
}

void UndergraduateStudentProfile::setGPA(double gpa) {
    if (gpa >= 0.0 && gpa <= 4.0) {
        this->gpa = gpa;
    } else {
        this->gpa = 0.0;
    }
}

void UndergraduateStudentProfile::displayProfile() const {
    std::cout << "Student Name: " << fullName << std::endl;
    std::cout << "Student ID: " << studentID << std::endl;
    std::cout << "GPA: " << gpa << std::endl;
}
```

